-- LESSON 1: THE DEFINITE ARTICLE
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  55, 1, 'grammar', 'The Definite Article', 'ὁ ἡ τό — Beginner',
  '{"concept":"The Definite Article","symbol":"ὁ ἡ τό","difficulty":"Beginner","overview":"Greek has only one article — the definite article (equivalent to the in English). There is no indefinite article (a/an) — that meaning is shown simply by the absence of the article. What makes Greek unique is that the article must agree with its noun in gender (masculine/feminine/neuter), number (singular/plural), and case (nominative, genitive, dative, accusative, vocative). This gives 24 distinct forms of the article.","key_points":["Greek has NO indefinite article — a God is simply θεός (no article)","ὁ is masculine, ἡ is feminine, τό is neuter","The article agrees with its noun in gender, number, and case","The presence of the article is often theologically significant: ὁ θεός = the God (the specific, true God)","The article can turn almost any word into a noun: ὁ λόγος = the word, οἱ πιστοί = the faithful ones"],"examples":[{"greek":"ὁ θεός","translation":"the God","reference":"John 1:1","note":"Masculine singular nominative — θεός is masculine"},{"greek":"ἡ ἀγάπη","translation":"the love","reference":"1 John 4:8","note":"Feminine singular nominative — ἀγάπη is feminine"},{"greek":"τὸ εὐαγγέλιον","translation":"the gospel","reference":"Mark 1:1","note":"Neuter singular nominative — εὐαγγέλιον is neuter"},{"greek":"οἱ μαθηταί","translation":"the disciples","reference":"Matthew 28:16","note":"Masculine plural nominative — the article changes to οἱ for plural"}],"tables":[{"title":"Definite Article — Singular","headers":["Case","Masc (ὁ)","Fem (ἡ)","Neut (τό)"],"rows":[["Nominative","ὁ","ἡ","τό"],["Genitive","τοῦ","τῆς","τοῦ"],["Dative","τῷ","τῇ","τῷ"],["Accusative","τόν","τήν","τό"]]},{"title":"Definite Article — Plural","headers":["Case","Masc (οἱ)","Fem (αἱ)","Neut (τά)"],"rows":[["Nominative","οἱ","αἱ","τά"],["Genitive","τῶν","τῶν","τῶν"],["Dative","τοῖς","ταῖς","τοῖς"],["Accusative","τούς","τάς","τά"]]}],"practice":[{"type":"identify","question":"What is the masculine singular nominative form of the Greek definite article?","answer":"ὁ"},{"type":"choice","question":"A Greek noun with NO article means:","options":["The noun (definite)","A/an (indefinite sense)","The noun is plural","The noun is a verb"],"answer":1},{"type":"choice","question":"John 1:1 says the Word WAS God (θεὸς ἦν ὁ λόγος). The word God (θεός) has no article here. Why is this theologically important?","options":["It means Jesus is not God","It shows the Word shares God''s divine nature without being identified as the entire Godhead","It is a mistake","It means God is indefinite"],"answer":1}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"ὁ λόγος (the Word, with article) vs θεὸς ἦν (was God, no article). The presence/absence of the article carries the entire Trinitarian argument here"},{"ref":"Matthew 6:9","text":"Our Father which art in heaven, Hallowed be thy name","note":"ὁ πατὴρ ἡμῶν — the Father of us (with article). The article on Father makes it specific — not any father but the definite, personal Father in heaven"}]'
);

-- LESSON 2: NOUN GENDER
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  56, 2, 'grammar', 'Noun Gender', 'Masculine, Feminine & Neuter — Beginner',
  '{"concept":"Noun Gender","symbol":"ὁ ἡ τό","difficulty":"Beginner","overview":"Every Greek noun has a fixed grammatical gender: masculine (ὁ), feminine (ἡ), or neuter (τό). Gender does not always match natural sex — for example, τέκνον (child) is neuter, and ψυχή (soul) is feminine. You must memorise each noun with its gender (always given by the article). Fortunately, there are patterns: most nouns ending in -ος are masculine, most ending in -η or -α are feminine, and most ending in -ον are neuter.","key_points":["Every noun has a fixed gender — must be memorised with the word","The article tells you the gender: ὁ = masculine, ἡ = feminine, τό = neuter","Gender patterns: -ος usually masculine, -η/-α usually feminine, -ον usually neuter","Natural sex and grammatical gender sometimes differ (τέκνον = child is neuter)","Adjectives and articles must AGREE in gender with their noun"],"examples":[{"greek":"ὁ λόγος","translation":"the word (masculine)","reference":"John 1:1","note":"-ος ending → typically masculine"},{"greek":"ἡ ἀγάπη","translation":"the love (feminine)","reference":"1 Cor 13:13","note":"-η ending → typically feminine"},{"greek":"τὸ πνεῦμα","translation":"the spirit (neuter)","reference":"John 4:24","note":"Irregular — πνεῦμα is neuter despite referring to the personal Holy Spirit"},{"greek":"ἡ ψυχή","translation":"the soul (feminine)","reference":"Matt 16:26","note":"-η ending → feminine"}],"tables":[{"title":"Common Gender Patterns","headers":["Ending","Gender","Article","Example"],"rows":[["-ος",  "Masculine","ὁ",  "ὁ λόγος (word)"],["-ης / -ης","Masculine","ὁ","ὁ μαθητής (disciple)"],["-η",  "Feminine", "ἡ",  "ἡ ἀγάπη (love)"],["-α",  "Feminine", "ἡ",  "ἡ καρδία (heart)"],["-ον", "Neuter",   "τό", "τὸ εὐαγγέλιον (gospel)"],["-μα", "Neuter",   "τό", "τὸ πνεῦμα (spirit)"]]}],"practice":[{"type":"identify","question":"What article tells you a noun is feminine?","answer":"ἡ"},{"type":"choice","question":"The word εὐαγγέλιον (gospel) ends in -ον. What gender is it likely to be?","options":["Masculine","Feminine","Neuter","It varies"],"answer":2},{"type":"choice","question":"τὸ πνεῦμα (the Spirit) is grammatically neuter, yet the Holy Spirit is a Person. What does this tell us about grammatical gender?","options":["The Spirit is an impersonal force","Grammatical gender is not the same as natural sex — the Spirit''s personhood is shown by other features like pronouns","The Spirit is less than a person","Greek grammar contradicts Christian theology"],"answer":1}]}',
  '[{"ref":"John 4:24","text":"God is a Spirit: and they that worship him must worship him in spirit and in truth","note":"τὸ πνεῦμα ὁ θεός — Spirit (neuter τό) is equated with God (masculine ὁ). Grammatical gender does not restrict personal divine attributes"},{"ref":"John 14:26","text":"But the Comforter, which is the Holy Ghost, whom the Father will send in my name","note":"The pronoun ἐκεῖνος (that one, masculine) is used for the Spirit (πνεῦμα, neuter) — Jesus deliberately uses a masculine pronoun to assert the Spirit''s personhood over grammatical gender"}]'
);

-- LESSON 3: NOUN CASES
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  57, 3, 'grammar', 'The Five Noun Cases', 'Function determines ending — Beginner',
  '{"concept":"The Five Noun Cases","symbol":"Ν Γ Δ Α Ν","difficulty":"Beginner","overview":"Greek nouns change their endings (called inflections or declensions) to show their grammatical function in a sentence. This system of endings is called cases. Greek has 5 cases: Nominative (subject), Genitive (possession/of), Dative (indirect object/to/for/by), Accusative (direct object), and Vocative (direct address). Because the ending shows function, Greek word order is very flexible — a word can be moved for emphasis without changing meaning.","key_points":["Nominative: the subject doing the action — ὁ θεός ἀγαπᾷ (God loves)","Genitive: possession or association — τοῦ θεοῦ (of God)","Dative: indirect object, means, or location — τῷ θεῷ (to/for God)","Accusative: the direct object receiving the action — τὸν θεόν (God as object)","Vocative: direct address — ὦ θεέ! (O God!)","Because endings show function, Greek word order is flexible — emphasis, not grammar, drives order"],"examples":[{"greek":"ὁ θεὸς ἀγαπᾷ τὸν κόσμον","translation":"God loves the world","reference":"John 3:16","note":"θεός = nominative (subject); κόσμον = accusative (object). The endings tell you who loves and who is loved"},{"greek":"ἡ χάρις τοῦ θεοῦ","translation":"the grace of God","reference":"Romans 5:15","note":"τοῦ θεοῦ = genitive (of God) — the genitive shows the source/possessor"},{"greek":"πιστεύω εἰς τὸν υἱὸν τοῦ θεοῦ","translation":"I believe into the Son of God","reference":"Galatians 2:20","note":"υἱόν = accusative (object of the preposition εἰς); θεοῦ = genitive (of God)"}],"tables":[{"title":"The Five Cases and Their Functions","headers":["Case","Question it answers","Function","Article (masc sg)"],"rows":[["Nominative","Who? What?","Subject of verb","ὁ"],["Genitive","Of whom? Whose?","Possession, source, association","τοῦ"],["Dative","To/for/by whom?","Indirect object, means, location","τῷ"],["Accusative","Whom? What?","Direct object of verb","τόν"],["Vocative","O ___!","Direct address","(ὦ)"]]}],"practice":[{"type":"identify","question":"Which case marks the subject of a verb in Greek?","answer":"Nominative"},{"type":"choice","question":"In John 3:16 God loved the world, the word world (κόσμον) is in what case — because it receives the action of loving?","options":["Nominative","Genitive","Dative","Accusative"],"answer":3},{"type":"choice","question":"ἡ χάρις τοῦ θεοῦ means the grace of God. The word God (θεοῦ) is in which case, showing possession/source?","options":["Nominative","Genitive","Dative","Accusative"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"For God so loved the world, that he gave his only begotten Son","note":"ὁ θεός (nom) — subject; τὸν κόσμον (acc) — object; τὸν υἱόν (acc) — object of gave. Cases unlock the grammar of the most famous verse in the Bible"},{"ref":"Romans 8:28","text":"And we know that all things work together for good to them that love God","note":"τοῖς ἀγαπῶσιν τὸν θεόν — to them that love (dative, indirect object) God (accusative, direct object). Cases show who receives the benefit and who receives the love"}]'
);

-- LESSON 4: FIRST DECLENSION NOUNS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  58, 4, 'grammar', 'First Declension Nouns', 'Mostly feminine — ἀγάπη pattern — Beginner',
  '{"concept":"First Declension Nouns","symbol":"-η / -α endings","difficulty":"Beginner","overview":"Greek nouns are grouped into three declension patterns based on their endings. First declension nouns mostly end in -η or -α in the nominative singular and are predominantly feminine. They follow a regular, predictable pattern. Key first declension words include ἀγάπη (love), ψυχή (soul), εἰρήνη (peace), and ἐκκλησία (church) — some of the most theologically important NT words.","key_points":["First declension: mostly feminine, ending in -η or -α (nominative singular)","The genitive singular always ends in -ης or -ας","The dative singular ends in -ῃ or -ᾳ","The accusative singular ends in -ην or -αν","Plural endings are the same for all first declension nouns: -αι, -ῶν, -αις, -ᾱς","A few first declension nouns are masculine (ending -ης or -ας): μαθητής, προφήτης"],"examples":[{"greek":"ἡ ἀγάπη (love)","translation":"Nom: ἀγάπη · Gen: ἀγάπης · Dat: ἀγάπῃ · Acc: ἀγάπην","reference":"1 Corinthians 13","note":"The ἀγάπη pattern — pure first declension feminine"},{"greek":"ἡ ψυχή (soul)","translation":"Nom: ψυχή · Gen: ψυχῆς · Dat: ψυχῇ · Acc: ψυχήν","reference":"Matthew 16:26","note":"Same pattern as ἀγάπη — note how the accent moves"},{"greek":"ὁ μαθητής (disciple)","translation":"Nom: μαθητής · Gen: μαθητοῦ · Dat: μαθητῇ · Acc: μαθητήν","reference":"Matthew 28:19","note":"Masculine first declension — notice the genitive takes -οῦ not -ης"}],"tables":[{"title":"First Declension: ἀγάπη (feminine)","headers":["Case","Singular","Plural"],"rows":[["Nominative","ἀγάπη","ἀγάπαι"],["Genitive","ἀγάπης","ἀγαπῶν"],["Dative","ἀγάπῃ","ἀγάπαις"],["Accusative","ἀγάπην","ἀγάπας"]]}],"practice":[{"type":"identify","question":"What case ending marks the genitive singular of a first declension feminine noun like ἀγάπη?","answer":"-ης (ἀγάπης)"},{"type":"choice","question":"Most first declension nouns are which gender?","options":["Masculine","Feminine","Neuter","Mixed"],"answer":1},{"type":"choice","question":"Which of these is a masculine first declension noun?","options":["ἀγάπη (love)","ψυχή (soul)","μαθητής (disciple)","εἰρήνη (peace)"],"answer":2}]}',
  '[{"ref":"1 Corinthians 13:13","text":"And now abideth faith, hope, charity, these three; but the greatest of these is charity","note":"ἀγάπη — nominative singular first declension. The greatest virtue in Paul''s famous trilogy takes the most fundamental first declension form"},{"ref":"John 14:27","text":"Peace I leave with you, my peace I give unto you","note":"εἰρήνην — accusative singular first declension (object of give). Christ''s parting gift is in the accusative — something He actively gives to us"}]'
);

-- LESSON 5: SECOND DECLENSION NOUNS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  59, 5, 'grammar', 'Second Declension Nouns', 'Mostly masculine — λόγος & ἔργον patterns — Beginner',
  '{"concept":"Second Declension Nouns","symbol":"-ος / -ον endings","difficulty":"Beginner","overview":"Second declension nouns end in -ος (masculine) or -ον (neuter) in the nominative singular. This is the largest and most regular Greek declension, containing many key theological words: λόγος (Word), κύριος (Lord), νόμος (law), κόσμος (world), σταυρός (cross), and οὐρανός (heaven). The masculine and neuter forms are identical except in nominative, accusative, and vocative.","key_points":["Masculine second declension: -ος nominative singular (ὁ λόγος)","Neuter second declension: -ον nominative singular (τὸ ἔργον)","Neuter rule: nominative and accusative are ALWAYS identical in neuter nouns","The genitive singular ends in -ου for both masculine and neuter","Second declension contains the most common Greek nouns","Key vocab: λόγος, κύριος, νόμος, κόσμος, δοῦλος, ἀδελφός, ἄνθρωπος"],"examples":[{"greek":"ὁ λόγος (word)","translation":"Nom: λόγος · Gen: λόγου · Dat: λόγῳ · Acc: λόγον","reference":"John 1:1","note":"The standard masculine second declension pattern — memorise this!"},{"greek":"ὁ κόσμος (world)","translation":"Nom: κόσμος · Gen: κόσμου · Dat: κόσμῳ · Acc: κόσμον","reference":"John 3:16","note":"Same exact pattern as λόγος — once you know one, you know them all"},{"greek":"τὸ ἔργον (work)","translation":"Nom: ἔργον · Gen: ἔργου · Dat: ἔργῳ · Acc: ἔργον","reference":"John 17:4","note":"Neuter: nominative = accusative (both -ον). Same dative and genitive as masculine"}],"tables":[{"title":"Second Declension: λόγος (masc) and ἔργον (neut)","headers":["Case","Masc Sg","Masc Pl","Neut Sg","Neut Pl"],"rows":[["Nominative","λόγος","λόγοι","ἔργον","ἔργα"],["Genitive","λόγου","λόγων","ἔργου","ἔργων"],["Dative","λόγῳ","λόγοις","ἔργῳ","ἔργοις"],["Accusative","λόγον","λόγους","ἔργον","ἔργα"]]}],"practice":[{"type":"identify","question":"What ending marks the genitive singular of a second declension noun (like λόγος)?","answer":"-ου (λόγου)"},{"type":"choice","question":"In neuter second declension nouns, which two cases always have identical forms?","options":["Nominative and genitive","Genitive and dative","Nominative and accusative","Dative and accusative"],"answer":2},{"type":"choice","question":"Which of these is a second declension masculine noun?","options":["ἀγάπη (love)","λόγος (word)","πνεῦμα (spirit)","εἰρήνη (peace)"],"answer":1}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"ὁ λόγος — nominative (subject). τοῦ θεοῦ would be genitive. Every case of this second declension noun carries theological weight in John''s prologue"},{"ref":"John 3:16","text":"For God so loved the world","note":"τὸν κόσμον — accusative singular (object of loved). The world (κόσμος, second declension masculine) is the object of God''s love. The -ν ending marks it as accusative"}]'
);

-- LESSON 6: THIRD DECLENSION NOUNS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  60, 6, 'grammar', 'Third Declension Nouns', 'All three genders — σάρξ & πνεῦμα patterns — Beginner',
  '{"concept":"Third Declension Nouns","symbol":"-ς / - endings","difficulty":"Beginner","overview":"The third declension is the most diverse of the three, containing nouns of all three genders. Nominative singulars vary widely, making these harder to recognise. The key identifier is the genitive singular, which always ends in -ος (not -ου like second declension). Third declension includes some crucial NT words: σάρξ (flesh), πίστις (faith), πνεῦμα (spirit), σωτήρ (Saviour), and πατήρ (Father).","key_points":["Third declension has nouns of all three genders","Genitive singular always ends in -ος (e.g. σαρκός, πίστεως, πνεύματος)","The dative plural always ends in -σι(ν)","Nominative singular forms vary greatly — no single pattern","Drop the genitive -ος to find the stem: σάρξ → σαρκ-; πίστις → πίστε-","Neuter third declension follows the neuter rule: nominative = accusative"],"examples":[{"greek":"ἡ σάρξ (flesh)","translation":"Nom: σάρξ · Gen: σαρκός · Dat: σαρκί · Acc: σάρκα","reference":"John 1:14","note":"Genitive -ός reveals the true stem: σαρκ-. The nominative σάρξ looks different!"},{"greek":"ἡ πίστις (faith)","translation":"Nom: πίστις · Gen: πίστεως · Dat: πίστει · Acc: πίστιν","reference":"Hebrews 11:1","note":"The -ις/-εως pattern is common for abstract nouns like ἐκκλησία, κρίσις, σωτηρία"},{"greek":"τὸ πνεῦμα (spirit)","translation":"Nom: πνεῦμα · Gen: πνεύματος · Dat: πνεύματι · Acc: πνεῦμα","reference":"John 4:24","note":"Neuter -μα nouns are very common; genitive always -ματος"}],"tables":[{"title":"Third Declension Key Patterns","headers":["Word","Nom Sg","Gen Sg (→stem)","Pattern name"],"rows":[["flesh","σάρξ","σαρκός → σαρκ-","labial/velar stem"],["faith","πίστις","πίστεως → πιστε-","-ις/-εως pattern"],["spirit","πνεῦμα","πνεύματος → πνευματ-","-μα/-ματος pattern"],["Saviour","σωτήρ","σωτῆρος → σωτηρ-","liquid stem"]]}],"practice":[{"type":"identify","question":"What ending always marks the genitive singular of a third declension noun?","answer":"-ος (e.g. σαρκός, πνεύματος, πίστεως)"},{"type":"choice","question":"John 1:14 says the Word became flesh (σάρξ). How would you find the stem of this third declension word?","options":["Remove the -ξ","Look at the genitive: σαρκός → stem is σαρκ-","Add -ος to the nominative","Use the dative form"],"answer":1},{"type":"choice","question":"Neuter third declension nouns follow which rule?","options":["Nominative ends in -ος","Genitive and dative are always the same","Nominative and accusative are always identical","Dative ends in -ῃ"],"answer":2}]}',
  '[{"ref":"John 1:14","text":"And the Word was made flesh, and dwelt among us","note":"σάρξ — third declension nominative. The eternal λόγος (second declension) became σάρξ (third declension) — two different declension patterns united in the Incarnation"},{"ref":"Galatians 5:17","text":"For the flesh lusteth against the Spirit, and the Spirit against the flesh","note":"ἡ σάρξ κατὰ τοῦ πνεύματος — flesh (third declension) against the Spirit (third declension genitive πνεύματος). The great inner conflict of the Christian life described in two third declension words"}]'
);

-- LESSON 7: ADJECTIVES
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  61, 7, 'grammar', 'Greek Adjectives', 'Agreement in gender, number & case — Beginner',
  '{"concept":"Greek Adjectives","symbol":"ἀγαθός ἀγαθή ἀγαθόν","difficulty":"Beginner","overview":"Greek adjectives must agree with their noun in three features: gender, number, and case. This is called concord. An adjective has 24 possible forms (3 genders × 2 numbers × 4 cases, roughly). Most adjectives follow first-and-second declension patterns (masculine/neuter = second declension; feminine = first declension). Two positions: attributive (inside the article-noun bracket) and predicate (outside, with no article or separated by a form of to be).","key_points":["Adjectives agree with their noun in gender, number, AND case — all three must match","Attributive position: ὁ ἀγαθὸς ἄνθρωπος = the good man (article-adj-noun)","Predicate position: ὁ ἄνθρωπος ἀγαθός ἐστιν = the man IS good (adj outside article)","Most NT adjectives follow 2-1-2 declension: masc/neut = 2nd declension, fem = 1st","Common adjectives: ἀγαθός (good), πιστός (faithful), ἅγιος (holy), αἰώνιος (eternal), πᾶς (all)","The adjective πᾶς (all, every) is a 3rd-1st-3rd declension — irregular but essential"],"examples":[{"greek":"ὁ ἀγαθὸς ποιμήν","translation":"the good shepherd","reference":"John 10:11","note":"Attributive position — adjective between article and noun, all masculine nominative"},{"greek":"ὁ θεὸς ἀγαθός ἐστιν","translation":"God is good","reference":"Mark 10:18","note":"Predicate position — adjective outside the article, making a statement about the noun"},{"greek":"ζωὴν αἰώνιον","translation":"eternal life","reference":"John 3:16","note":"αἰώνιον agrees with ζωήν — both accusative feminine singular"}],"tables":[{"title":"Adjective ἀγαθός (good)","headers":["Case","Masc","Fem","Neut"],"rows":[["Nom Sg","ἀγαθός","ἀγαθή","ἀγαθόν"],["Gen Sg","ἀγαθοῦ","ἀγαθῆς","ἀγαθοῦ"],["Dat Sg","ἀγαθῷ","ἀγαθῇ","ἀγαθῷ"],["Acc Sg","ἀγαθόν","ἀγαθήν","ἀγαθόν"],["Nom Pl","ἀγαθοί","ἀγαθαί","ἀγαθά"]]}],"practice":[{"type":"identify","question":"An adjective must agree with its noun in which three features?","answer":"Gender, number, and case"},{"type":"choice","question":"In the phrase ὁ ἀγαθὸς ποιμήν (the good shepherd), the adjective ἀγαθός is in attributive position. How do you recognise attributive position?","options":["The adjective comes after the noun","The adjective is inside the article-noun bracket","The adjective has no article","The adjective is a predicate"],"answer":1},{"type":"choice","question":"ζωὴν αἰώνιον (eternal life) — both words end in -ον/-ην. What does this agreement tell you?","options":["Both are second declension nouns","The adjective αἰώνιον agrees with ζωήν — both are feminine accusative singular","Both are neuter","They are in the nominative case"],"answer":1}]}',
  '[{"ref":"John 10:11","text":"I am the good shepherd: the good shepherd giveth his life for the sheep","note":"ὁ ποιμὴν ὁ καλός — the shepherd the good (double article attributive). Jesus uses the adjective καλός (beautiful-good, noble) rather than ἀγαθός — emphasising visible, excellent goodness"},{"ref":"John 3:16","text":"that whosoever believeth in him should not perish, but have everlasting life","note":"ζωὴν αἰώνιον — eternal life (accusative feminine). The two-word phrase that defines the promise of the gospel — adjective and noun in perfect grammatical agreement"}]'
);

-- LESSON 8: PERSONAL PRONOUNS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  62, 8, 'grammar', 'Personal Pronouns', 'ἐγώ σύ αὐτός — Beginner',
  '{"concept":"Personal Pronouns","symbol":"ἐγώ σύ αὐτός","difficulty":"Beginner","overview":"Greek personal pronouns decline for case (like nouns) but also encode person (1st, 2nd, 3rd) and number. First person: ἐγώ (I), ἡμεῖς (we). Second person: σύ (you singular), ὑμεῖς (you plural). Third person: αὐτός/αὐτή/αὐτό (he/she/it), αὐτοί/αὐταί/αὐτά (they). A key feature: Greek VERBS already encode person and number in their endings, so subject pronouns are often omitted — when they appear, they carry emphasis.","key_points":["Greek verbs carry person/number in their endings — subject pronouns are often omitted","When ἐγώ or σύ appears explicitly, it is emphatic: I (not someone else)","The I AM (ἐγώ εἰμι) statements of Jesus are emphatic — the explicit ἐγώ is emphatic deity language","αὐτός = he/him; αὐτή = she/her; αὐτό = it; αὐτοί = they","αὐτός can also mean same or himself as an intensive pronoun","The genitive of the personal pronoun shows possession: αὐτοῦ = of him/his"],"examples":[{"greek":"ἐγώ εἰμι ὁ ποιμὴν ὁ καλός","translation":"I AM the good shepherd","reference":"John 10:11","note":"ἐγώ is emphatic — Jesus is asserting His identity, not just stating a fact. The I AM echoes Exodus 3:14"},{"greek":"σύ εἶ ὁ Χριστός","translation":"You are the Christ","reference":"Matthew 16:16","note":"σύ is emphatic — Peter''s great confession singles out Jesus as THE Christ"},{"greek":"αὐτός σώσει τὸν λαὸν αὐτοῦ","translation":"He himself will save his people","reference":"Matthew 1:21","note":"αὐτός emphatic (he himself); αὐτοῦ = his (genitive possession)"}],"tables":[{"title":"Personal Pronouns — Nominative","headers":["Person","Singular","Plural"],"rows":[["1st","ἐγώ (I)","ἡμεῖς (we)"],["2nd","σύ (you)","ὑμεῖς (you all)"],["3rd Masc","αὐτός (he)","αὐτοί (they)"],["3rd Fem","αὐτή (she)","αὐταί (they)"],["3rd Neut","αὐτό (it)","αὐτά (they)"]]},{"title":"1st Person — ἐγώ","headers":["Case","Singular","Plural"],"rows":[["Nominative","ἐγώ","ἡμεῖς"],["Genitive","ἐμοῦ / μου","ἡμῶν"],["Dative","ἐμοί / μοι","ἡμῖν"],["Accusative","ἐμέ / με","ἡμᾶς"]]}],"practice":[{"type":"identify","question":"In the seven I AM statements of Jesus (John 6:35, 8:12, 10:9, etc.), what is the emphatic significance of the explicit ἐγώ?","answer":"It is emphatic — I (and no one else). It echoes God''s self-declaration in Exodus 3:14 (I AM THAT I AM)"},{"type":"choice","question":"Greek verbs already encode person in their endings. When the subject pronoun ἐγώ is used explicitly anyway, what does it indicate?","options":["It is always required","It is emphatic — stressing I as opposed to someone else","It is a mistake","It indicates past tense"],"answer":1},{"type":"choice","question":"αὐτοῦ is the genitive of αὐτός. What does it mean in Matthew 1:21 (he shall save his people)?","options":["To him","He himself","His / of him","By him"],"answer":2}]}',
  '[{"ref":"John 8:58","text":"Jesus said unto them, Verily, verily, I say unto you, Before Abraham was, I am","note":"ἐγώ εἰμι — the most explosive I AM claim. The explicit ἐγώ before εἰμι is emphatic and deliberate. The audience understood the divine Name claim — they picked up stones to stone Him"},{"ref":"Galatians 2:20","text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me","note":"ζῶ δὲ οὐκέτι ἐγώ — I no longer live. The explicit ἐγώ is emphatic — Paul means specifically the old self, which has died. Then ζῇ δὲ ἐν ἐμοὶ Χριστός — Christ lives in me (ἐμοί, dative)"}]'
);

-- LESSON 9: PREPOSITIONS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  63, 9, 'grammar', 'Greek Prepositions', 'ἐν εἰς ἐκ ἀπό διά — Beginner',
  '{"concept":"Greek Prepositions","symbol":"ἐν εἰς ἐκ","difficulty":"Beginner","overview":"Greek prepositions show the relationship between nouns/pronouns and the rest of a sentence (location, direction, means, etc.). Crucially, Greek prepositions govern specific cases — they tell you which case to use for the noun that follows. Some prepositions take only one case; others take two or three depending on meaning. Understanding which case a preposition governs is essential for NT interpretation.","key_points":["Prepositions govern specific cases — the case affects the meaning","ἐν (in) always takes the dative case","εἰς (into, for the purpose of) always takes the accusative case","ἐκ/ἐξ (out of, from) always takes the genitive case","ἀπό (away from) always takes the genitive","διά (through/because of) takes genitive (agent/means) or accusative (reason)","πρός (toward, with) takes accusative; κατά (against/according to) takes genitive or accusative"],"examples":[{"greek":"ἐν Χριστῷ","translation":"in Christ","reference":"Ephesians 1:3","note":"ἐν + dative — the most common phrase in Paul''s letters (appears 90+ times). Location/sphere: our entire spiritual life exists in the sphere of Christ"},{"greek":"βαπτίζω εἰς τὸ ὄνομα","translation":"baptize into the name","reference":"Matthew 28:19","note":"εἰς + accusative — direction/purpose. Baptism is a movement INTO identity with the Name of the Trinity"},{"greek":"ἐκ τοῦ κόσμου","translation":"out of the world","reference":"John 17:15","note":"ἐκ + genitive — movement out from. Jesus does not pray to take us out of the world but to protect us in it"},{"greek":"διὰ πίστεως","translation":"through faith","reference":"Ephesians 2:8","note":"διά + genitive — means/agent. Grace reaches us THROUGH faith as its channel"}],"tables":[{"title":"Key Prepositions and Their Cases","headers":["Preposition","Meaning","Case Governed"],"rows":[["ἐν","in, by, with, among","Dative only"],["εἰς","into, to, for (purpose)","Accusative only"],["ἐκ / ἐξ","out of, from (source)","Genitive only"],["ἀπό","from, away from","Genitive only"],["πρός","toward, with, at","Accusative only"],["διά","through (means); because of (reason)","Gen; Acc"],["κατά","against; according to","Gen; Acc"],["ὑπό","by (agent); under","Gen; Acc"],["περί","concerning, about","Gen; Acc"],["ὑπέρ","on behalf of, above","Gen; Acc"]]}],"practice":[{"type":"identify","question":"What case does ἐν (in) always take?","answer":"The dative case"},{"type":"choice","question":"Paul writes ἐν Χριστῷ (in Christ) over 90 times. What does the preposition ἐν with dative express here?","options":["Movement toward Christ","Location/sphere — our entire life is situated within Christ","Origin from Christ","The purpose of Christ"],"answer":1},{"type":"choice","question":"εἰς τὸ ὄνομα (into the name) — Matthew 28:19 on baptism. εἰς takes the accusative. What does the directional sense of εἰς add to baptism?","options":["Baptism is a past event only","Baptism is a movement INTO identification with the Name — a relational union","Baptism is just a symbol with no directional meaning","Baptism requires a formula not a relationship"],"answer":1}]}',
  '[{"ref":"Ephesians 1:3","text":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ","note":"ἐν Χριστῷ — in Christ (dative). Paul''s great declaration of positional blessings. Every spiritual blessing we have exists in the sphere of our union with Christ"},{"ref":"Romans 8:1","text":"There is therefore now no condemnation to them which are in Christ Jesus","note":"ἐν Χριστῷ Ἰησοῦ — in Christ Jesus (dative). The most liberating no condemnation in Scripture is grounded entirely in the preposition ἐν and the dative — our position in Christ"}]'
);

